// // This module implements a 2-to-1 multiplexer where OUT reflects the value of B when SEL is low (0) and the value of A when SEL is high (1).
module top_module(
    OUT,
    A,
    B,
    SEL
);output OUT;
    input A;
    input B;
    input SEL;

    wire NOT_SEL;

    assign NOT_SEL = ~SEL;

    assign OUT = (A & NOT_SEL) | (B & SEL);

endmodule
